const config = { ...$json };
for (const required of ['repoOwner', 'repoName', 'currentVersion', 'currentRef', 'githubApiBase']) {
  if (!String(config[required] || '').trim()) {
    throw new Error(`Missing required GitHub release input: ${required}`);
  }
}
return { json: { ...config, tagsPerPage: Math.min(Math.max(Number(config.tagsPerPage || 100), 1), 100) } };

const inputs = $('Normalize GitHub input').first().json;
const tagPages = $input.all().map((item) => item.json);

function parseVersion(value) {
  const match = String(value || '').trim().match(/^(\d+)\.(\d+)\.(\d+)$/);
  return match ? { major: Number(match[1]), minor: Number(match[2]), patch: Number(match[3]) } : null;
}

function versionFromTag(tagName) {
  const match = String(tagName || '').match(/(?:^|[^0-9])(\d+\.\d+\.\d+)(?=$|[^0-9])/);
  return match ? parseVersion(match[1]) : null;
}

function compareVersion(a, b) {
  return a.major - b.major || a.minor - b.minor || a.patch - b.patch;
}

function sameVersion(a, b) {
  return a.major === b.major && a.minor === b.minor && a.patch === b.patch;
}

function buildRank(tagName) {
  const match = String(tagName || '').match(/(?:^|[-_])b(\d{6,14})(?:$|[-_])/i);
  return match ? Number(match[1]) : -1;
}

const tagEntries = tagPages.flatMap((page) => Array.isArray(page) ? page : [page]);
const tags = tagEntries.filter((tag) => tag && typeof tag.name === 'string');
const tagFetchErrors = tagEntries
  .filter((entry) => !Array.isArray(entry) && entry && typeof entry === 'object' && !entry.name && (entry.error || entry.message))
  .map((entry) => ({
    message: entry.message || entry.error || 'Unknown tag fetch error',
    statusCode: entry.statusCode || entry.code || null,
    raw: entry,
  }));

const currentVersion = String(inputs.currentVersion || '').trim();
const currentRef = String(inputs.currentRef || currentVersion).trim();
const current = parseVersion(currentVersion);
const previousTagOverride = String(inputs.previousTagOverride || '').trim() || null;
const previousVersionOverride = String(inputs.previousVersionOverride || '').trim() || null;

if (!currentVersion) {
  throw new Error('currentVersion is empty. Expected a semantic version like 1.2.28.');
}
if (!current) {
  throw new Error(`Invalid currentVersion "${currentVersion}". Expected x.y.z.`);
}
if (!currentRef) {
  throw new Error('currentRef is empty. Set the GitHub tag, branch, or SHA for the release.');
}

const warnings = [];
if (tagFetchErrors.length) {
  warnings.push(`GitHub tags request returned ${tagFetchErrors.length} error item(s).`);
}

let previousTag = previousTagOverride;
let previousVersion = previousVersionOverride;
let resolveStatus = previousTag ? 'override' : 'resolved';
let previousCandidates = [];

if (!previousTag) {
  const candidates = tags
    .map((tag) => ({ ...tag, parsed: versionFromTag(tag.name) }))
    .filter((tag) => tag.parsed && compareVersion(tag.parsed, current) < 0);

  if (candidates.length === 0) {
    warnings.push(`No previous Git tag was found before ${currentVersion}.`);
    resolveStatus = 'unresolved';
  } else {
    const previousParsed = candidates
      .map((tag) => tag.parsed)
      .sort((a, b) => compareVersion(b, a))[0];

    previousCandidates = candidates
      .filter((tag) => sameVersion(tag.parsed, previousParsed))
      .sort((a, b) => buildRank(b.name) - buildRank(a.name) || String(b.name).localeCompare(String(a.name)));

    previousTag = previousCandidates[0]?.name || null;
    previousVersion = `${previousParsed.major}.${previousParsed.minor}.${previousParsed.patch}`;

    if (!previousTag) {
      warnings.push('A previous version was identified but no concrete tag could be selected.');
      resolveStatus = 'unresolved';
    }
  }
}

return [{
  json: {
    ...inputs,
    currentVersion,
    currentRef,
    currentTag: currentRef,
    previousVersion: previousVersion || null,
    previousTag: previousTag || null,
    compareBase: previousTag || null,
    compareHead: currentRef,
    tagResolve: {
      status: resolveStatus,
      tagsReturned: tags.length,
      selectedPreviousTag: previousTag || null,
      previousTagCandidates: previousCandidates.map((tag) => tag.name),
      selectedCurrentRef: currentRef,
      warnings,
      fetchErrors: tagFetchErrors,
      usedOverride: Boolean(previousTagOverride),
    },
  },
}];

const base = $('Resolve previous Git tag').first().json;
const pages = $input.all().map((item) => item.json);

const bySha = new Map();
for (const page of pages) {
  for (const commit of Array.isArray(page?.commits) ? page.commits : []) {
    if (!commit?.sha || bySha.has(commit.sha)) continue;
    bySha.set(commit.sha, {
      sha: commit.sha,
      url: commit.html_url || null,
      message: commit.commit?.message || null,
      date: commit.commit?.author?.date || null,
      author: {
        name: commit.commit?.author?.name || null,
        email: commit.commit?.author?.email || null,
        login: commit.author?.login || null,
      },
      committer: {
        name: commit.commit?.committer?.name || null,
        email: commit.commit?.committer?.email || null,
        login: commit.committer?.login || null,
      },
      parents: (commit.parents || []).map((parent) => parent.sha).filter(Boolean),
    });
  }
}

const compareFetchErrors = pages
  .filter((page) => page && typeof page === 'object' && !Array.isArray(page) && !page.commits && (page.error || page.message))
  .map((page) => ({
    message: page.message || page.error || 'Unknown compare error',
    statusCode: page.statusCode || page.code || null,
    raw: page,
  }));

const reportedTotal = Math.max(0, ...pages.map((page) => Number(page?.total_commits) || 0));
const commits = [...bySha.values()];
const warnings = [];

if (!base.compareBase) {
  warnings.push('Previous Git tag could not be resolved. GitHub compare may be incomplete or empty.');
}
if (reportedTotal > 0 && commits.length !== reportedTotal) {
  warnings.push(`GitHub compare reported ${reportedTotal} commit(s), but ${commits.length} unique commit(s) were consolidated.`);
}
if (compareFetchErrors.length) {
  warnings.push(`GitHub compare produced ${compareFetchErrors.length} error item(s).`);
}

const first = pages.find((page) => page && typeof page === 'object' && !Array.isArray(page) && (page.status || page.html_url || page.total_commits != null)) || {};
const compareMeta = {
  status: first.status || null,
  aheadBy: first.ahead_by ?? null,
  behindBy: first.behind_by ?? null,
  totalCommits: reportedTotal || commits.length,
  htmlUrl: first.html_url || null,
  pagesFetched: pages.length,
  commitsFetched: commits.length,
  warnings,
  fetchErrors: compareFetchErrors,
};

if (commits.length === 0) {
  return [{ json: { ...base, compareMeta, noCommit: true, commit: null } }];
}

return commits.map((commit) => ({
  json: {
    ...base,
    compareMeta,
    noCommit: false,
    commit,
  },
}));

const source = $('Compile all commits').item.json;
const detail = $json;
const fallback = source.commit || {};

function extractSisKeys(text) {
  const matches = [...String(text || '').matchAll(/\bSIS[\s_-]*(\d+)\b/gi)];
  return [...new Set(matches.map((match) => `SIS-${match[1]}`))];
}

function compactPerson(gitPerson, githubUser) {
  return {
    name: gitPerson?.name || null,
    email: gitPerson?.email || null,
    login: githubUser?.login || null,
  };
}

const hasDetail = Boolean(
  detail &&
  typeof detail === 'object' &&
  detail.sha &&
  detail.commit &&
  !detail.error
);

const responseError = hasDetail
  ? null
  : {
      message:
        detail?.error?.message ||
        detail?.message ||
        detail?.error ||
        'GitHub commit detail was not returned.',
      statusCode:
        detail?.statusCode ||
        detail?.status ||
        detail?.code ||
        detail?.error?.statusCode ||
        null,
    };

const sha = hasDetail ? detail.sha : fallback.sha || null;
const message = hasDetail
  ? detail.commit?.message || fallback.message || null
  : fallback.message || null;

const parents = hasDetail
  ? (Array.isArray(detail.parents)
      ? detail.parents.map((parent) => parent?.sha).filter(Boolean)
      : [])
  : (Array.isArray(fallback.parents) ? fallback.parents.filter(Boolean) : []);

const isMergeCommit =
  parents.length > 1 ||
  /^merge\b/i.test(String(message || '').trim());

const files = hasDetail && Array.isArray(detail.files)
  ? detail.files.map((file) => ({
      filename: file?.filename || null,
      previousFilename: file?.previous_filename || null,
      status: file?.status || null,
      additions: file?.additions ?? null,
      deletions: file?.deletions ?? null,
      changes: file?.changes ?? null,
      patch: file?.patch || null,
      blobUrl: file?.blob_url || null,
      rawUrl: file?.raw_url || null,
    }))
  : [];

const messageSisKeys = isMergeCommit ? [] : extractSisKeys(message);

return {
  json: {
    kind: 'commitRecord',
    context: {
      repoOwner: source.repoOwner || null,
      repoName: source.repoName || null,
      githubApiBase: source.githubApiBase || null,
      jiraBaseUrl: source.jiraBaseUrl || null,
      jiraApiVersion: source.jiraApiVersion || '2',
      currentVersion: source.currentVersion || null,
      currentRef: source.currentRef || null,
      previousTag: source.previousTag || null,
      compareMeta: source.compareMeta || null,
    },
    github: {
      commit: {
        sha,
        url: hasDetail ? detail.html_url || fallback.url || null : fallback.url || null,
        message,
        messageTruncated: false,
        date: hasDetail
          ? detail.commit?.author?.date || fallback.date || null
          : fallback.date || null,
        author: hasDetail
          ? compactPerson(detail.commit?.author, detail.author)
          : fallback.author || {},
        committer: hasDetail
          ? compactPerson(detail.commit?.committer, detail.committer)
          : fallback.committer || {},
        parents,
        isMergeCommit,
        isReportable: Boolean(sha) && !isMergeCommit,
        stats: hasDetail ? detail.stats || null : null,
        files,
        filesTotal: files.length,
        filesTruncated: false,
        detailStatus: hasDetail ? 'retrieved' : 'failed',
        fetchError: responseError,
      },
    },
    originSisKeys: messageSisKeys,
    sisDetection: {
      message: messageSisKeys,
      patches: [],
      ignoredBecauseMerge: isMergeCommit,
      note: isMergeCommit
        ? 'Technical merge commit excluded from SIS detection and reporting.'
        : 'SIS detected from the GitHub commit message.',
    },
  },
};

const detailed = $input.all().map((item) => item.json);

if (detailed.length === 0) {
  return [{
    json: {
      kind: 'githubCollectorResult',
      hasCommits: false,
      collectorStatus: 'noCommitRecordsProduced',
      warning: 'GitHub collector completed without commit records.',
    },
  }];
}

const context = detailed.find((row) => row.context)?.context || {};
const stats = {
  total: detailed.length,
  retrieved: detailed.filter((row) => row.github?.commit?.detailStatus === 'retrieved').length,
  failed: detailed.filter((row) => row.github?.commit?.detailStatus === 'failed').length,
  commitsWithFiles: detailed.filter((row) => (row.github?.commit?.files || []).length > 0).length,
  filesTotal: detailed.reduce(
    (sum, row) => sum + Number(row.github?.commit?.filesTotal || 0),
    0
  ),
};

return detailed.map((record) => ({
  json: {
    ...record,
    collectorStats: stats,
    context: {
      ...context,
      collectorStats: stats,
    },
  },
}));
